// Resolve Input — front door for the e-learning engine. Accepts a standalone Course
// Form submission, a /command (executeWorkflow), or a magazine-derived course, and
// normalises them into one contract. Also builds the SHARED, style- and length-aware
// AI prompt (systemPrompt + userPrompt) referenced by both the Claude and Ollama nodes
// so there is a single source of truth for the content schema.
const i = $input.first() ? ($input.first().json || {}) : {};
function pick(){ for(var k=0;k<arguments.length;k++){ var v=arguments[k]; if(v!=null && String(v).trim()!=='') return String(v).trim(); } return ''; }

// ---- topic ----
let custom = pick(i['Custom topic'], i.customTopic); let drop = pick(i['Topic'], i.topic); if(/^custom/i.test(drop)) drop='';
let t = pick(custom, drop, i.query, i.text); t = t.replace(/^\/[a-zA-Z]+\b/, '').trim();
if(!t) t = ($env.DEFAULT_AWARENESS_TOPIC || 'phishing');

// ---- style ----  quiz | gamified | puzzle | scenario  (Surprise me -> random)
const STYLES = ['quiz','gamified','puzzle','scenario'];
function styleKey(s){ s=(s||'').toLowerCase();
  if(/surprise|random|any/.test(s)) return STYLES[Math.floor(Math.random()*STYLES.length)];
  if(/scenario|branch|story|choose/.test(s)) return 'scenario';
  if(/puzzle|spot|phish|hunt|flag/.test(s)) return 'puzzle';
  if(/game|gamif|arcade|soc|triage|mission/.test(s)) return 'gamified';
  if(/quiz|q&a|q and a|qa|knowledge|test/.test(s)) return 'quiz';
  return '';
}
let style = styleKey(pick(i['Style'], i.style));
if(!style) style = styleKey($env.ELEARNING_DEFAULT_STYLE) || 'gamified';

// ---- length ----  micro | standard | full -> content counts
function lenKey(s){ s=(s||'').toLowerCase();
  if(/micro|short|quick|bite|mini/.test(s)) return 'micro';
  if(/full|long|deep|comprehensive|standardplus/.test(s)) return 'full';
  if(/standard|medium|normal|default/.test(s)) return 'standard';
  return '';
}
let length = lenKey(pick(i['Length'], i.length));
if(!length) length = lenKey($env.ELEARNING_DEFAULT_LENGTH) || 'standard';
const COUNTS = {
  micro:    { sec:'2 to 3', q:'3 to 4', items:'4 to 6',  scenes:'3 to 4', puzzles:'3 to 4' },
  standard: { sec:'4',      q:'4 to 5', items:'6 to 8',  scenes:'4 to 5', puzzles:'4 to 5' },
  full:     { sec:'5 to 6', q:'5 to 6', items:'8 to 12', scenes:'5 to 6', puzzles:'5 to 6' }
}[length];

// ---- other options ----
const fmt = pick(i['Format'], i.format).toLowerCase();
let format='Both'; if(fmt.indexOf('scorm')>=0 && fmt.indexOf('html')<0) format='SCORM'; else if(fmt.indexOf('html')>=0 && fmt.indexOf('scorm')<0) format='HTML';
const pm = parseInt(pick(i['Pass mark (%)'], i['Pass mark'], i.passMark),10);
const imgSel = pick(i['Section images'], i.illustrate);
let illustrate; if(imgSel) illustrate = !/^(no|false|off|0)/i.test(imgSel); else illustrate = (($env.ELEARNING_SECTION_IMAGES||'true').toString().toLowerCase()!=='false');

// Magazine-derived course passes grounding `source`, an explicit `title`, and the
// publication/course ids that tie completion back to the dashboard.
const source = pick(i.source, i.brief);
const title = pick(i.title);
if(!custom && !drop && title) t = title;
const publicationId = pick(i.publicationId);
const courseId = pick(i.courseId);
const audience = pick(i['Audience'], i.audience) || 'All staff';
const passMark = isNaN(pm)?80:pm;

// ---------- shared AI prompt (style + length aware) ----------
const SECT = 'sections (' + COUNTS.sec + ' items, each {heading, body (2-4 short paragraphs separated by single newline characters), keyPoints (2-4 short bullet strings), scene (ONE vivid sentence describing a realistic modern-office scene that visually illustrates this section, written for an illustrator: describe the people, setting and action; do NOT mention any on-screen text, screens of text, or logos)})';
const QUES = 'questions (' + COUNTS.q + ' knowledge-check items, each {q, options (array of exactly 4 short strings), answer (0-based index of the correct option), why (one-sentence explanation)})';
const ACTIVITY = {
  gamified: 'gameItems (' + COUNTS.items + ' items for a SOC-triage training game, each {from (who it appears to be from - a name and/or email address, a phone caller, or e.g. \'IT Helpdesk\'), subject (a short subject line or the gist of the request, max 80 characters), body (1-2 short sentences with the message or request), clues (2-4 very short things a careful person would notice - a mix of genuine red flags and reassuring or neutral details), action (\'allow\' if it is safe normal business, \'report\' if it is suspicious or phishing and should be reported to security, or \'block\' if it is clearly malicious or an unsafe request to refuse), why (one sentence the learner sees after deciding), level (1, 2 or 3 to group items into difficulty tiers), boss (true for exactly ONE climactic targeted-attack scenario such as CEO/BEC gift-card fraud, otherwise omit)}). Aim for a roughly even spread of allow/report/block.',
  puzzle: 'puzzles (' + COUNTS.puzzles + ' "spot the red flags" items, each {kind (\'email\', \'sms\' or \'web\'), from (apparent sender, caller or website/URL), subject (subject line, message gist or page title, max 80 characters), body (1-2 short sentences of the message or page), elements (4-6 items the learner inspects, each {label (what part this is, e.g. \'Sender address\', \'Link\', \'Greeting\', \'Urgency\', \'Attachment\', \'Tone\'), value (the concrete content of that part), suspicious (true if it is a genuine red flag, false if it is innocent), why (one short sentence explaining why)}), verdict (\'phish\' if the overall item is malicious/suspicious, or \'legit\' if it is genuinely safe)}). Mix phish and legit items, and within each item mix suspicious and innocent elements so it is not all-or-nothing.',
  scenario: 'scenario (a branching decision story, an object {intro (1-2 sentences setting the scene and the learner\'s role), scenes (' + COUNTS.scenes + ' decision points, each {situation (2-3 sentences describing what is happening right now), choices (exactly 3 items, each {text (the action the learner could take, first person), correct (true for the single best choice), feedback (one or two sentences of coaching shown after this choice, written as the consequence of taking it), risk (\'low\', \'medium\' or \'high\' - the security risk this choice creates)})}), outro (1-2 sentences wrapping up the lesson)}). Exactly one choice per scene is correct; wrong choices still continue the story with honest consequences.'
};
const styleLine = style==='quiz'
  ? 'This module is a concise Q&A / knowledge-check style: rely on the sections and questions; do NOT include any game, puzzle or scenario block.'
  : ('This module is the "' + style + '" interactive style. In addition to the common keys, also include: ' + (ACTIVITY[style]||''));
const systemPrompt = 'You are an instructional designer creating a short, engaging, interactive security-awareness e-learning module. For the given topic and audience produce a SINGLE valid JSON object. Common keys: title; intro (2-3 sentences on why this matters to the learner and the organisation); ' + SECT + '; ' + QUES + '. ' + styleLine + ' Use plain, engaging, non-technical language tailored to the audience. Do NOT use markdown code fences. Output ONLY the JSON object.';
const userPrompt = (source
  ? ('Base this module STRICTLY on the following staff security-awareness magazine content. Ground every section, question and activity ONLY in it.\n\n' + source)
  : ('Create an interactive e-learning module on the topic: ' + t))
  + ' Audience: ' + audience + '. Knowledge-check pass mark: ' + passMark + '%.';

return [{ json: {
  topic:t, title:title, source:source, style:style, length:length,
  publicationId:publicationId, courseId:courseId, audience:audience,
  passMark:passMark, format:format, illustrate:illustrate,
  systemPrompt:systemPrompt, userPrompt:userPrompt,
  date:new Date().toISOString().slice(0,10), client:($env.CLIENT_NAME||'').toString()
} }];

const j = $json || {};
let raw = '';
if (j.message && j.message.content) raw = j.message.content;
else if (j.content && j.content[0] && j.content[0].text) raw = j.content[0].text;
let data = null;
try { data = JSON.parse(raw.replace(/^```(?:json)?\s*/i,'').replace(/\s*```$/i,'')); }
catch (e) { try { const m = raw.match(/\{[\s\S]*\}/); if (m) data = JSON.parse(m[0]); } catch (e2) { data = null; } }
const r = $('Resolve Input').first().json;
const style = r.style || 'gamified';
const STYLE = 'Cinematic, semi-realistic editorial illustration set in a bright modern corporate office. Polished, professional and calm mood; soft natural window light with a warm key light; teal and deep-navy colour grade; shallow depth of field; clean wide composition with generous empty space near the top. Diverse professional people in business-casual attire, natural expressions. ';
const NEG = ' No text, no words, no letters, no numbers, no logos, no signage, no watermark, no user-interface screenshots, no charts.';
if (data && !data.title && r.title) data.title = r.title;
const sections = (data && data.sections) || [];
const imagePrompts = sections.map(function(s){ var scene = (s && (s.scene || s.heading)) || ('a workplace scene about ' + (r.topic||'security awareness')); return STYLE + 'Scene: ' + scene + '.' + NEG; });
const coverPrompt = 'Wide cinematic hero cover image for a premium corporate security-awareness course about ' + (r.topic||'security awareness') + '. ' + STYLE + 'Establishing wide shot of a modern office that conveys trust, focus and vigilance; dramatic but professional lighting; strong empty space on the left for a title.' + NEG;
// The night-shift SOC backplate is only used by the "gamified" arcade style, so we
// only spend an image generation on it for that style (other styles reuse the cover
// and section heroes for their context art). Gritty, photoreal, empty environment so
// the DOM console reads clearly on top.
const gameBgPrompt = (style === 'gamified')
  ? ('Photoreal cinematic wide shot of a dark security operations centre (SOC) at night, empty with no people. A large rain-streaked window looks out over a rainy city skyline; rows of monitors glow warm amber and teal against deep navy shadows; moody volumetric lighting, soft bokeh, film grain, atmospheric haze. Centre of the frame is calm and uncluttered. ' + NEG)
  : '';
return [{ json: { data:data, topic:r.topic, audience:r.audience, passMark:r.passMark, format:r.format, illustrate:r.illustrate, style:style, length:r.length, imagePrompts:imagePrompts, coverPrompt:coverPrompt, gameBgPrompt:gameBgPrompt, date:r.date, client:r.client, publicationId:r.publicationId, courseId:r.courseId } }];

const j = $json || {};
const sectionPrompts = j.imagePrompts || [];
const coverPrompt = j.coverPrompt || '';
const gameBgPrompt = j.gameBgPrompt || '';
let sections = sectionPrompts.map(function(){ return ''; });
let cover = '';
let gameBg = '';
const key = $env.OPENAI_IMAGE_API_KEY || $env.OPENAI_API_KEY;
if (j.illustrate && key) {
  const H = this.helpers;
  const base = ($env.OPENAI_BASE_URL || 'https://api.openai.com/v1');
  const model = ($env.IMAGE_MODEL || 'gpt-image-2');
  const size = ($env.ELEARNING_IMAGE_SIZE || '1536x1024');
  const gen = async function(p){
    try {
      const resp = await H.httpRequest({ method:'POST', url: base + '/images/generations',
        headers: { Authorization: 'Bearer ' + key, 'Content-Type': 'application/json' },
        body: { model: model, prompt: p, size: size, quality: ($env.ELEARNING_IMAGE_QUALITY || 'high'), n: 1 }, json: true, timeout: 180000 });
      const b64 = resp && resp.data && resp.data[0] && resp.data[0].b64_json;
      return b64 ? ('data:image/png;base64,' + b64) : '';
    } catch (e) { return ''; }
  };
  if (coverPrompt) cover = await gen(coverPrompt);
  for (let k = 0; k < sectionPrompts.length; k++) { sections[k] = await gen(sectionPrompts[k]); }
  // Backplate for the SOC triage game (optional; gated by the same key/illustrate
  // flag and skippable via ELEARNING_GAME_IMAGE=false). Degrades to a CSS backdrop
  // in the renderer when empty.
  if (gameBgPrompt && (($env.ELEARNING_GAME_IMAGE || 'true').toString().toLowerCase() !== 'false')) { gameBg = await gen(gameBgPrompt); }
}
return [{ json: Object.assign({}, j, { images: { cover: cover, sections: sections, gameBg: gameBg } }) }];

// E-learning renderer — gamified 16:9 enterprise lesson player. Cover, name entry,
// mission briefing, animated sections (Ken Burns heroes, animated SVG accents),
// XP + levels + achievement badges, and a self-paced "Night-shift SOC triage"
// mini-game: the learner inspects each queued item (sender, message, clues) and
// sorts it Allow / Report / Block. Relaxed (no-fail) by default with an optional
// Challenge mode (decision timer, lives, power-ups, score chase); levels + a boss
// finale; a handler ("Jarvis") on comms; local high scores. A three.js atmosphere
// layer (gpt-image backplate, rain, parallax, bloom) sits behind the crisp DOM
// console and degrades to a CSS backdrop when WebGL is unavailable, so all gameplay
// text stays readable. Knowledge check with animated score ring, confetti, and an
// embedded completion certificate. SCORM 1.2 aware (quiz score reported to LMS).
const d = $json.data || {};
const topic = $json.topic || 'Security Awareness';
const date = $json.date || new Date().toISOString().slice(0,10);
const client = ($json.client || '').toString();
const passMark = Number($json.passMark) || 80;
const format = $json.format || 'Both';
const style = ($json.style || 'gamified');
const lengthKey = ($json.length || 'standard');
const images = ($json.images && typeof $json.images === 'object' && !Array.isArray($json.images))
  ? { cover: ($json.images.cover||''), sections: ($json.images.sections||[]), gameBg: ($json.images.gameBg||'') }
  : { cover:'', sections:(Array.isArray($json.images)?$json.images:[]), gameBg:'' };
function esc(s){ return (s==null?'':String(s)).replace(/[&<>]/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;'})[c];}); }
const title = d.title || (topic + ' — Awareness Module');
const brand = client ? client : 'Security Awareness';
const publicationId = ($json.publicationId || '').toString();
const courseId = ($json.courseId || '').toString();

// Env-driven brand theme (platform standard).
function jbHex(v,df){v=String(v||'').trim();return /^#[0-9a-fA-F]{6}$/.test(v)?v:df;}
var JB_PRI=jbHex($env.BRAND_PRIMARY,'#0A1A2F'),JB_ACC=jbHex($env.BRAND_ACCENT,'#0E7C86'),JB_GOLD=jbHex($env.BRAND_GOLD,'#C9A24B');

// three.js — vendored library inlined so the package is fully self-contained
// (works inside locked-down LMS networks); CDN fallback only if the mount is
// missing; the game itself degrades to a 2D DOM version when WebGL/THREE fail.
let _fs = null; try { _fs = require('fs'); } catch (e) {}
let THREE_SRC = '';
try { THREE_SRC = _fs.readFileSync('/config/vendor/three.min.js','utf8'); } catch (e) { THREE_SRC = ''; }

// --- animated SVG icon set (stroke = brand accent; .pz group is animated in CSS) ---
function ic(inner){ return '<svg viewBox="0 0 24 24" fill="none" stroke="'+JB_ACC+'" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"><g class="pz">'+inner+'</g></svg>'; }
const ICONS = {
  shield: ic('<path d="M12 3l7 3v5c0 4.5-3 7.6-7 9-4-1.4-7-4.5-7-9V6z"/><path d="M9 12l2 2 4-4"/>'),
  lock:   ic('<rect x="5" y="11" width="14" height="9" rx="2"/><path d="M8 11V8a4 4 0 0 1 8 0v3"/>'),
  mail:   ic('<rect x="3" y="5" width="18" height="14" rx="2"/><path d="M3 7l9 6 9-6"/>'),
  eye:    ic('<path d="M2 12s4-7 10-7 10 7 10 7-4 7-10 7S2 12 2 12z"/><circle cx="12" cy="12" r="3"/>'),
  alert:  ic('<path d="M12 3l9 16H3z"/><path d="M12 10v4"/><circle cx="12" cy="16.7" r="0.6" fill="'+JB_ACC+'" stroke="none"/>'),
  key:    ic('<circle cx="8" cy="12" r="4"/><path d="M12 12h9M18 12v4M21 12v3"/>'),
  phone:  ic('<path d="M6 3h4l2 5-3 2a11 11 0 0 0 5 5l2-3 5 2v4a2 2 0 0 1-2 2A17 17 0 0 1 4 6a2 2 0 0 1 2-3z"/>'),
  id:     ic('<rect x="3" y="5" width="18" height="14" rx="2"/><circle cx="9" cy="11" r="2"/><path d="M14 10h4M14 13h4M6 16h8"/>'),
  check:  ic('<path d="M5 13l4 4 10-10"/>')
};
function pickIcon(h){ h=(h||'').toLowerCase();
  if(/phish|email|mail|bec|message|invoice/.test(h)) return 'mail';
  if(/password|mfa|auth|credential|key|login/.test(h)) return 'key';
  if(/call|phone|vish|voice/.test(h)) return 'phone';
  if(/pretext|imperson|identity|profile/.test(h)) return 'id';
  if(/spot|sign|watch|red flag|detect|recognis|recogniz/.test(h)) return 'eye';
  if(/report|incident|respond|attack|suspect|breach|fraud/.test(h)) return 'alert';
  if(/lock|secure|encrypt|device|protect|data/.test(h)) return 'lock';
  return 'shield';
}
const sections = (d.sections||[]).map(function(s){ var o=Object.assign({}, s); o.iconKey=pickIcon((s.heading||'')+' '+(s.scene||'')); return o; });
// Game items: AI-written SOC triage tickets. Enriched schema
// { from, subject, body, clues[], action:'allow'|'report'|'block', why, level, boss }
// with backward compatibility for the legacy { text, risky, why } shape (mapped to
// allow/block). If the model returned none the mission is skipped gracefully (we
// never fabricate training content here).
function elArr(a){ return Array.isArray(a)?a:[]; }
const gameItems = elArr(d.gameItems).map(function(g){ g=g||{};
  var action=String(g.action||'').toLowerCase();
  if(action!=='allow'&&action!=='report'&&action!=='block') action = g.risky ? 'block' : 'allow';
  var body=String(g.body||g.text||'').trim();
  var clues=elArr(g.clues).map(function(c){return String(c||'').trim();}).filter(Boolean).slice(0,4);
  var lvl=parseInt(g.level,10); lvl=(lvl>=1&&lvl<=9)?lvl:0;
  return { from:String(g.from||'').trim().slice(0,70), subject:String(g.subject||'').trim().slice(0,90),
    body:body.slice(0,240), clues:clues, action:action, why:String(g.why||'').trim().slice(0,220),
    level:lvl, boss:!!g.boss };
}).filter(function(g){ return g.body || g.subject; }).slice(0,14);

// Spot-the-Phish puzzles (element-tagging model — robust, no fragile substring hunts):
// { kind, from, subject, body, elements:[{label,value,suspicious,why}], verdict }.
const puzzles = elArr(d.puzzles).map(function(p){ p=p||{};
  var els = elArr(p.elements).map(function(e){ e=e||{}; return { label:String(e.label||'').trim().slice(0,40), value:String(e.value||'').trim().slice(0,180), suspicious:!!e.suspicious, why:String(e.why||'').trim().slice(0,220) }; }).filter(function(e){ return e.value; }).slice(0,7);
  var verdict=String(p.verdict||'').toLowerCase(); if(verdict!=='phish'&&verdict!=='legit') verdict = els.some(function(e){return e.suspicious;}) ? 'phish' : 'legit';
  var kind=String(p.kind||'').toLowerCase(); kind=/sms|text/.test(kind)?'sms':(/web|site|url|page/.test(kind)?'web':'email');
  return { kind:kind, from:String(p.from||'').trim().slice(0,90), subject:String(p.subject||'').trim().slice(0,90), body:String(p.body||'').trim().slice(0,300), elements:els, verdict:verdict };
}).filter(function(p){ return p.elements.length>=2; }).slice(0,8);

// Branching scenario: { intro, scenes:[{situation, choices:[{text,correct,feedback,risk}]}], outro }
const scn = (d.scenario && typeof d.scenario==='object' && !Array.isArray(d.scenario)) ? d.scenario : null;
const scenario = scn ? { intro:String(scn.intro||'').trim().slice(0,400), outro:String(scn.outro||'').trim().slice(0,400),
  scenes: elArr(scn.scenes).map(function(s){ s=s||{};
    var ch = elArr(s.choices).map(function(c){ c=c||{}; var rk=String(c.risk||'').toLowerCase(); if(rk!=='low'&&rk!=='medium'&&rk!=='high') rk=c.correct?'low':'medium';
      return { text:String(c.text||'').trim().slice(0,200), correct:!!c.correct, feedback:String(c.feedback||'').trim().slice(0,280), risk:rk }; }).filter(function(c){ return c.text; }).slice(0,4);
    if(ch.length && !ch.some(function(c){return c.correct;})) ch[0].correct=true;
    return { situation:String(s.situation||'').trim().slice(0,500), choices:ch }; }).filter(function(s){ return s.situation && s.choices.length>=2; }).slice(0,8)
} : null;

// --- premium certificate furniture (gold seal, corner flourishes, crest, watermark) ---
function certInitials(s){ var w=String(s||'').trim().split(/\s+/).filter(Boolean); var a=(w[0]||'S')[0]+((w[1]||w[0]||'A')[0]||''); return a.toUpperCase().slice(0,2); }
function makeSeal(init, topText, botText){
  var cx=110, cy=104, spikes=30, R1=96, R2=86, pts=[];
  for(var i=0;i<spikes*2;i++){ var r=(i%2===0)?R1:R2; var a=(Math.PI/spikes)*i - Math.PI/2; pts.push((cx+r*Math.cos(a)).toFixed(1)+','+(cy+r*Math.sin(a)).toFixed(1)); }
  var burst='<polygon points="'+pts.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="1"/>';
  function laurel(side){ var g='',n=8; for(var i=0;i<n;i++){ var t=i/(n-1); var ang=(-150 + t*120)*Math.PI/180; var rad=58; var x=cx + side*(rad*Math.cos(ang)*0.62 + 6); var y=cy + 30 - rad*Math.sin(ang)*0.95; var rot=(side>0?-50:50)+(t*60*side); g+='<ellipse cx="'+x.toFixed(1)+'" cy="'+y.toFixed(1)+'" rx="9" ry="3.6" fill="#E3C766" transform="rotate('+rot.toFixed(1)+' '+x.toFixed(1)+' '+y.toFixed(1)+')"/>'; } return g; }
  function star(scx,scy,R,r,p2){ var p=[]; for(var i=0;i<p2*2;i++){ var rr=(i%2===0)?R:r; var a=(Math.PI/p2)*i - Math.PI/2; p.push((scx+rr*Math.cos(a)).toFixed(1)+','+(scy+rr*Math.sin(a)).toFixed(1)); } return '<polygon points="'+p.join(' ')+'" fill="url(#gold)" stroke="#8A6A22" stroke-width="0.6"/>'; }
  return '<svg class="seal" viewBox="0 0 220 250" xmlns="http://www.w3.org/2000/svg">'
   +'<defs><radialGradient id="gold" cx="50%" cy="36%" r="68%"><stop offset="0" stop-color="#F6E6A8"/><stop offset="50%" stop-color="#D9B45A"/><stop offset="100%" stop-color="#A9842F"/></radialGradient></defs>'
   +'<path d="M83 150 L70 244 L98 222 L110 240 L122 222 L150 244 L137 150 Z" fill="'+JB_ACC+'"/>'
   +'<path d="M83 150 L78 186 L137 186 L137 150 Z" fill="#0a5b63"/>'
   +burst
   +'<circle cx="'+cx+'" cy="'+cy+'" r="80" fill="url(#gold)"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="#0E2233"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="72" fill="none" stroke="#E3C766" stroke-width="2" stroke-dasharray="1.5 5"/>'
   +'<circle cx="'+cx+'" cy="'+cy+'" r="60" fill="none" stroke="#C9A24B" stroke-width="1"/>'
   +laurel(-1)+laurel(1)+star(cx,cy-18,16,7,5)
   +'<text x="'+cx+'" y="'+(cy+14)+'" text-anchor="middle" font-family="Georgia,serif" font-size="20" font-weight="bold" fill="#F6E6A8" letter-spacing="1">'+esc(init)+'</text>'
   +'<text x="'+cx+'" y="'+(cy+34)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="8.5" fill="#E3C766" letter-spacing="2">'+esc(botText)+'</text>'
   +'<text x="'+cx+'" y="'+(cy-44)+'" text-anchor="middle" font-family="Arial,sans-serif" font-size="9" fill="#E3C766" letter-spacing="3">'+esc(topText)+'</text>'
   +'</svg>';
}
function makeCorner(cls){ return '<svg class="cn '+cls+'" viewBox="0 0 80 80"><path d="M6 74 C6 36 36 6 74 6" fill="none" stroke="#C9A24B" stroke-width="2"/><path d="M14 74 C14 42 42 14 74 14" fill="none" stroke="#C9A24B" stroke-width="1"/><circle cx="6" cy="74" r="3.5" fill="#C9A24B"/></svg>'; }
const certSeal = makeSeal(certInitials(brand), 'CERTIFIED', 'EXCELLENCE');
const certCorners = makeCorner('tl')+makeCorner('tr')+makeCorner('bl')+makeCorner('br');
