  Object.keys(map).map(Number).sort(function(a,b){return a-b;}).forEach(function(L){levels.push(shuffle(map[L]));});}
 else {var sz=normal.length<=6?3:4;var pool=shuffle(normal.slice());for(var i=0;i<pool.length;i+=sz)levels.push(pool.slice(i,i+sz));}
